const { ApolloServer, gql } = require('apollo-server');
const WebSocket = require('ws');

// Define the schema
const typeDefs = gql`
  type ChatMessage {
    id: ID!
    text: String!
    roomId: ID!
    userId: ID!
  }

  type Subscription {
    newChatMessage(roomId: ID!): ChatMessage!
  }

  type Query {
    chatRooms: [ID!]!
  }
`;

// Define the resolvers
const resolvers = {
  Query: {
    chatRooms: () => ['room1', 'room2'],
  },
  Subscription: {
    newChatMessage: {
      subscribe: (parent, { roomId }, { pubsub }) =>
        pubsub.asyncIterator(`NEW_CHAT_MESSAGE_${roomId}`),
    },
  },
};

// Create a WebSocket connection
const wss = new WebSocket.Server({ port: 3000 });

// Set up Apollo Server with WebSocket support
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: () => ({ pubsub }),
});

server.applyMiddleware({ app: require('express')() });

// Handle incoming WebSocket connections
wss.on('connection', (ws) => {
  console.log('Client connected');

  // Handle incoming messages from clients
  ws.on('message', (data) => {
    const { roomId, text } = JSON.parse(data);
    console.log(`Received message in room ${roomId}: ${text}`);

    // Publish the new chat message to all subscribers of that room
    server.pubsub.publish(`NEW_CHAT_MESSAGE_${roomId}`, {
      newChatMessage: { id: 1, text, roomId, userId: 'user1' },
    });
  });

  // Handle disconnections
  ws.on('close', () => console.log('Client disconnected'));
});